def _to_json_safe(obj):

    """Recursively convert any object (including AttrDict/dict subclasses) to plain Python types."""

    if hasattr(obj, '__class__') and obj.__class__.__name__ == 'AttrDict':

        obj = dict(obj)

    if isinstance(obj, dict):

